import{c as e,Q as r,j as s,m as n}from"./chunks/framework.BXc4yaFE.js";const d=JSON.parse('{"title":"Natural-Language Agent Harnesses (NLAH)","description":"","frontmatter":{"title":"Natural-Language Agent Harnesses (NLAH)","source_tier":"P"},"headers":[],"relativePath":"research/agent-harness/references/2603.25723-natural-language-agent-harnesses-arxiv.md","filePath":"research/agent-harness/references/2603.25723-natural-language-agent-harnesses-arxiv.md","lastUpdated":1779894392000}'),t={name:"research/agent-harness/references/2603.25723-natural-language-agent-harnesses-arxiv.md"};function l(i,a,o,h,g,u){return r(),s("div",null,[...a[0]||(a[0]=[n('<h1 id="natural-language-agent-harnesses-nlah" tabindex="-1">Natural-Language Agent Harnesses (NLAH) <a class="header-anchor" href="#natural-language-agent-harnesses-nlah" aria-label="Permalink to &quot;Natural-Language Agent Harnesses (NLAH)&quot;">​</a></h1><ul><li><strong>arXiv</strong>: <a href="https://arxiv.org/abs/2603.25723" target="_blank" rel="noreferrer">https://arxiv.org/abs/2603.25723</a></li><li><strong>收錄日期</strong>: 2026-05-01</li><li><strong>發表</strong>: 2026-03</li><li><strong>重要性</strong>: Priority B — 解決 harness 可移植性問題的創新視角</li></ul><hr><h2 id="核心論點" tabindex="-1">核心論點 <a class="header-anchor" href="#核心論點" aria-label="Permalink to &quot;核心論點&quot;">​</a></h2><p>傳統 harness「深埋在控制器代碼中」，難以跨系統移植或科學研究。本論文提出用自然語言表達 harness 行為。</p><h2 id="兩個核心概念" tabindex="-1">兩個核心概念 <a class="header-anchor" href="#兩個核心概念" aria-label="Permalink to &quot;兩個核心概念&quot;">​</a></h2><h3 id="natural-language-agent-harnesses-nlahs" tabindex="-1">Natural-Language Agent Harnesses (NLAHs) <a class="header-anchor" href="#natural-language-agent-harnesses-nlahs" aria-label="Permalink to &quot;Natural-Language Agent Harnesses (NLAHs)&quot;">​</a></h3><ul><li>人類可讀的 harness 規範</li><li>可跨系統遷移的格式</li><li>版本控制友善</li><li>可科學比較與研究</li></ul><h3 id="intelligent-harness-runtime-ihr" tabindex="-1">Intelligent Harness Runtime (IHR) <a class="header-anchor" href="#intelligent-harness-runtime-ihr" aria-label="Permalink to &quot;Intelligent Harness Runtime (IHR)&quot;">​</a></h3><p>執行 NLAH 的運行時，通過三個機制：</p><ol><li><strong>顯式合約（Explicit Contracts）</strong>: 明確定義 harness 的行為邊界</li><li><strong>持久成品（Persistent Artifacts）</strong>: 跨 session 保持 harness 狀態</li><li><strong>輕量適配器（Lightweight Adapters）</strong>: 連接 harness 與不同模型/工具</li></ol><h2 id="解決的核心問題" tabindex="-1">解決的核心問題 <a class="header-anchor" href="#解決的核心問題" aria-label="Permalink to &quot;解決的核心問題&quot;">​</a></h2><ul><li>可移植性：harness 可在不同 agent 框架間遷移</li><li>可對比性：不同 harness 設計可以被科學比較</li><li>可研究性：harness 工程成為可重複的學術研究對象</li></ul><h2 id="與本-workspace-的關聯" tabindex="-1">與本 Workspace 的關聯 <a class="header-anchor" href="#與本-workspace-的關聯" aria-label="Permalink to &quot;與本 Workspace 的關聯&quot;">​</a></h2><p>本 workspace 的設計已接近 NLAH 精神：</p><ul><li>CLAUDE.md = Natural-Language Harness 規範</li><li><code>.claude/settings.json</code> = IHR 的顯式合約層</li><li>@rules 系統 = 輕量適配器（按需載入）</li></ul><p>NLAH 論文提供了<strong>理論依據</strong>說明為何「CLAUDE.md 作為 harness 規範」是正確的設計方向。</p><h2 id="參考連結" tabindex="-1">參考連結 <a class="header-anchor" href="#參考連結" aria-label="Permalink to &quot;參考連結&quot;">​</a></h2><ul><li>arXiv Abstract: <a href="https://arxiv.org/abs/2603.25723" target="_blank" rel="noreferrer">https://arxiv.org/abs/2603.25723</a></li></ul>',19)])])}const p=e(t,[["render",l]]);export{d as __pageData,p as default};
